head.script:
scwin.hid_chkshpCd = "";
scwin.hid_chklineCd = "";
scwin.shCo = "";

scwin.pre_RowPosition = 0;
scwin.pre_cntrNo = "";
scwin.pre_vehclNo = "";
scwin.pre_fullEmptyClsCd = "";
scwin.pre_chassisNo = "";

scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strPreDate = $c.date.addMonth(scwin.strCurDate, -1); //한달전
scwin.strYm = scwin.strPreDate.substring(0,6);

scwin.memJson = $c.data.getMemInfo();
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); //상위물류점소코드
scwin.loUpperLobranNm = $c.data.getMemInfo("loUpperLobranNm"); //상위물류점소
scwin.userId = scwin.memJson.userId;  //사용자
scwin.userClsCd = scwin.memJson.userClsCd;	// 사용자 구분코드
scwin.loginClntNo = $c.data.getMemInfo("clntNo") == null ? "-" : $c.data.getMemInfo("clntNo");
scwin.loginClntNm = $c.data.getMemInfo("clntNm") == null ? "" : $c.data.getMemInfo("clntNm"); //거래처명
scwin.wrkPlCd = $c.data.getMemInfo("wrkPlCd") == null ? "" :$c.data.getMemInfo("wrkPlCd");
scwin.cntrNo = $c.data.getMemInfo("cntrNo") == null ? "" :$c.data.getMemInfo("cntrNo");
scwin.odrNo = $c.data.getMemInfo("odrNo") == null ? "" :$c.data.getMemInfo("odrNo");
scwin.lineCd = $c.data.getMemInfo("lineCd") == null ? "" :$c.data.getMemInfo("lineCd");

scwin.ed_portCnt_onkeyup = function(e) {
    e.target.value = e.target.value.toUpperCase();
};
scwin.onpageload = function() {

    udc_fromToCalendar.setInitDate(scwin.strCurDate,scwin.strCurDate); //udc달력 형식

    //공통코드 적용()
    const codeOptions = [ 
        { grpCd : "SD060", compID : "lc_impExpClsCd"}, //수입/수출
        { grpCd : "SD113", compID : "lc_odrKndCd"}, //오더종류
        { grpCd : "OP171", compID : "lc_fullEmptyClsCd"}, //F/E
        { grpCd : "OP101", compID : "lc_siz"}, //SIZE/TYPE
        { grpCd : "OP102", compID : "lc_typ"}, //SIZE/TYPE
        { grpCd : "OP197", compID : "lc_crryInOutCd"}, //반출/반입
        { grpCd : "OP524", compID : "gr_Grid1:term"}, //TERM
    ];

    $c.data.setCommonCode(codeOptions);

    sbm_branch.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"+"&queryId=retriveLobranCd";
    $c.sbm.execute(sbm_branch);

    gr_Grid2.setStyle("display", "none"); // 그리드 숨기기
    chb_directExcludeYn.setValue("N");
};


scwin.onUdcCompleted = function() {

    let shCo = ed_shpCo.getValue();

    //udc control
    if( scwin.userClsCd != "01"){  //사용자가 협력업체 일때
        ed_shpCo.setValue(scwin.loginClntNo);
        ed_shpNm.setValue(scwin.loginClntNm);
        ed_shpCo.disabled(true);
        ed_shpCo.setStyle("background-color", "#dfdfdf");
        ed_shpCo.disabled(false);
        ed_shpNm.setStyle("background-color", "#dfdfdf");
    }

    scwin.f_setLine(shCo);
};


//공통(최종오더 값중에서 fillter 사용)
scwin.ondataload = function() { 

    let dltStr = "dlt_commonCodeSD113";
    let dlt = $c.gus.object(dltStr);
    $c.data.dataListFilter(dlt, "fltrCd1 == 'C' && cd != 'CA' && cd != 'CB' && cd != 'CK' && cd != 'CZ' && cd != 'M1'");
};

//초기화
scwin.btn_fieldClear_onclick = function (e) {

    $c.gus.cfInitObjects(tbl_cond,[])
    udc_fromToCalendar.setInitDate(scwin.strCurDate,scwin.strCurDate); //udc달력 형식;

    if(scwin.loUpperLobranCd == ""){
        lc_con_branCd.setSelectedIndex(0);
    }else{
        lc_con_branCd.setValue(scwin.loUpperLobranCd);
    }

    if(scwin.userClsCd != "01") {  //사용자가 협력업체 일때
        ed_shpCo.setValue(scwin.loginClntNo);
        ed_shpNm.setValue(scwin.loginClntNm);
    }

    scwin.f_setLine();
};

// 라인콤보 조회
scwin.f_setLine = function() {

    sbm_linelist.action = "/cm.zz.RetrieveComboCMD.do?sysCd=LineEBC&queryId=retrieveLineEachShpCoCdCombo&param1="+scwin.loginClntNo+"&param2="+scwin.userClsCd+"&param3="+ed_shpCo.getValue();
    $c.sbm.execute(sbm_linelist);
};

//사업장 change
scwin.sbm_branch_submitdone = async function() {

    ds_co_ds_branCd.sort("col1", 0);
    lc_con_branCd.setValue(scwin.loUpperLobranCd);

    //점소callback 
    sbm_wrkPlCd.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=retriveWrkLobranCd&param3="+lc_con_branCd.getValue();
    await $c.sbm.execute(sbm_wrkPlCd);

    lc_wrkPlCd.focus();
};

//점소 change
scwin.sbm_wrkPlCd_submitdone = function() {

    ds_wrkPlCd.sort("col1", 0);
	lc_wrkPlCd.setValue(scwin.wrkPlCd);

    if(scwin.userId == "PKE123")
	{
		lc_con_branCd.setValue("6AA");
		lc_wrkPlCd.setValue("6C01");

        lc_wrkPlCd.setDisabled(true);
 		lc_con_branCd.setDisabled(true);
	}
};

//점소 콤보 DataSet OnRowPosChanged Event
scwin.lc_con_branCd_onviewchange = function (info) {

    sbm_wrkPlCd.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=retriveWrkLobranCd&param3="+lc_con_branCd.getValue();
    $c.sbm.execute(sbm_wrkPlCd);

    lc_wrkPlCd.focus();
};

//ds_wrkPlCd OnRowPosChanged Event 발생시
scwin.lc_wrkPlCd_onviewchange = function (info) {

    let	v_wrkPlCd	= ds_wrkPlCd.getCellData(0, "col1");
	sbm_block.action = "/cm.zz.RetrieveComboCMD.do?sysCd=WorkPlaceEachGoodsEBC&queryId=retrivecBlockList&param1=" + v_wrkPlCd;

};

//조회
scwin.btn_retrieve_onclick = async function (e) {

    if (! await $c.gus.cfValidate([lc_con_branCd,lc_wrkPlCd,ed_stDt,ed_endDt])) {	// 작업장, 반출입
        return;
    }

    if (ed_stDt.getValue() > ed_endDt.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_endDt.focus();
        return;
    }

    //damaMap set.
    dma_QueryCondition.set("lobranCd",lc_con_branCd.getValue());   //점소
    dma_QueryCondition.set("wrkPlCd",lc_wrkPlCd.getValue());   // 작업장
    dma_QueryCondition.set("stDt",ed_stDt.getValue());     // 작업시작일
    dma_QueryCondition.set("endDt",ed_endDt.getValue());        // 작업종료일
    dma_QueryCondition.set("vsslCd",ed_vsslCd.getValue());        // 선박
    dma_QueryCondition.set("portcnt",ed_portCnt.getValue());     // 항차
    dma_QueryCondition.set("lineCd",lc_lineCd.getValue());        // 라인코드
    dma_QueryCondition.set("shpCoClntNo",ed_shpCo.getValue());        // 선사
    dma_QueryCondition.set("crryinoutClsCd",lc_crryInOutCd.getValue());     // 반출입구분
    dma_QueryCondition.set("impExpClsCd",lc_impExpClsCd.getValue());     // 수출입구분
    dma_QueryCondition.set("fullEmptyClsCd",lc_fullEmptyClsCd.getValue());  // F/E
    dma_QueryCondition.set("cntrSizCd",lc_siz.getValue());     // 사이즈
    dma_QueryCondition.set("cntrTypCd",lc_typ.getValue());     // 타입
    dma_QueryCondition.set("odrKndCd",lc_odrKndCd.getValue());// 오더종류
    dma_QueryCondition.set("bookingNo",ed_bookingNo.getValue());// 부킹넘버


    if(chb_directExcludeYn.getValue() == "Y"){
    	dma_QueryCondition.set("directExcludeYn","Y");
    }else{
    	dma_QueryCondition.set("directExcludeYn","N");
    }

    $c.sbm.execute(sbm_retrieve);
};

//line combo callback
scwin.sbm_linelist_submitdone = function() {
};

//조회 callback
scwin.sbm_retrieve_submitdone = function() {

    let nCnt = ds_Grid1.getRowCount();

	if( nCnt == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_WRN_002);

  	} else {
        gr_Grid1.setFocusedCell(0, 0);
        total.setValue(nCnt);
    }

    scwin.f_SetDataPut();

};

