//발행 btn
scwin.button_ozprint_onclick = async function (e) {

    if (!await $c.gus.cfValidate([lc_con_branCd,lc_wrkPlCd,ed_stDt,ed_endDt])) {	// 작업장, 반출입
		return;
	}

    if (ed_stDt.getValue() > ed_endDt.getValue()) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_endDt.focus();
        return;
    }

    let data = "";
    if (scwin.userClsCd != "01"){ //선사권한일 경우
        data = {
            reportName: "/ds/op/wrkrslts/cywrkrslts/op_301_01_48_1r.ozr",
            odiParam: {
                        conBranCd:		lc_con_branCd.getValue(),
                        conBranNm:		lc_con_branCd.getValue(),
                        wrkPlCd:		lc_wrkPlCd.getValue(),
                        vsslCd:		    ed_vsslCd.getValue(),
                        portCnt:		ed_portCnt.getValue(),
                        lineCd:		    lc_lineCd.getValue(),
                        crryInOutCd:	lc_crryInOutCd.getValue(),
                        impExpClsCd:	lc_impExpClsCd.getValue(),
                        fullEmptyClsCd:	lc_fullEmptyClsCd.getValue(),
                        siz:		    lc_siz.getValue(),
                        typ:		    lc_typ.getValue(),
                        stDt:		    ed_stDt.getValue(),
                        endDt:		    ed_endDt.getValue(),
                        odrKndCd:		lc_odrKndCd.getValue(),
                        shpCoClntNo:	ed_shpCo.getValue(),
                    },
            viewerParam: {
            useprogressbar: false,
            mode: "silent"
                },
            formParam: {
            //
                }
            }
            scwin.openPopup(data);
    }else{
        data = {
        reportName: "/ds/op/wrkrslts/cywrkrslts/op_301_01_48r.ozr",
        odiParam: {
                        conBranCd:		lc_con_branCd.getValue(),
                        conBranNm:		lc_con_branCd.getValue(),
                        wrkPlCd:		lc_wrkPlCd.getValue(),
                        vsslCd:		    ed_vsslCd.getValue(),
                        portCnt:		ed_portCnt.getValue(),
                        lineCd:		    lc_lineCd.getValue(),
                        crryInOutCd:	lc_crryInOutCd.getValue(),
                        impExpClsCd:	lc_impExpClsCd.getValue(),
                        fullEmptyClsCd:	lc_fullEmptyClsCd.getValue(),
                        siz:		    lc_siz.getValue(),
                        typ:		    lc_typ.getValue(),
                        stDt:		    ed_stDt.getValue(),
                        endDt:		    ed_endDt.getValue(),
                        odrKndCd:		lc_odrKndCd.getValue(),
                        shpCoClntNo:	ed_shpCo.getValue(),
                    },
        viewerParam: {
        useprogressbar: false,
        mode: "silent"
            },
        formParam: {
        //
            }
        }
        scwin.openPopup(data);
    }
};

scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };

    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//scwin.excelDw
scwin.excelDw = async function() {

    let options = {
        fileName : "Daily Cntr Movement.xlsx",
        sheetName : "Daily Cntr Movement"
    }

    let grdObj = gr_Grid1;

    let infoArr = {};

    if(ds_Grid1.getTotalRow() == 0) {  //전체total count
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            $c.data.downloadGridViewExcel(grdObj, options, infoArr)
        }
    }
};

//MOL발행
scwin.button_print_onclick = async function (e) {

    let options = {
        fileName : "Daily Cntr Movement.xlsx",
        sheetName : "Daily Cntr Movement"
    }

    let features = "copyHeader=yes,rowFrom=1,rowCnt=" + ds_Grid1.getRowCount();
    $c.gus.cfCopyDataSet(ds_Grid1, ds_Grid2, features);

    let grdObj = gr_Grid2;

    let infoArr = {};

    if(ds_Grid2.getTotalRow() == 0) {  //전체total count
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            $c.data.downloadGridViewExcel(grdObj, options, infoArr)
        }
    }
};
